      out.write("  <span id=\"motivationText\"></span>\r\n");
      out.write("\r\n");
      out.write("  <!-- JS libs -->\r\n");
      out.write("<script src=\"https://cdn.jsdelivr.net/npm/swiper@9/swiper-bundle.min.js\"></script>\r\n");
      out.write("<script src=\"https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js\"></script>\r\n");
      out.write("\r\n");
      out.write("<script>\r\n");
      out.write("//===== Swiper (Cinematic Carousel) =====\r\n");
      out.write("const heroSwiper = new Swiper('.swiper', {\r\n");
      out.write("  loop: true,\r\n");
      out.write("  speed: 1000,\r\n");
      out.write("  autoplay: { delay: 4000, disableOnInteraction: false },\r\n");
      out.write("  parallax: true,\r\n");
      out.write("  effect: 'slide',\r\n");
      out.write("  pagination: { el: '.swiper-pagination', clickable: true, dynamicBullets: true },\r\n");
      out.write("  navigation: { nextEl: '.swiper-button-next', prevEl: '.swiper-button-prev' },\r\n");
      out.write("  on: {\r\n");
      out.write("    slideChangeTransitionStart: function () {\r\n");
      out.write("      document.querySelectorAll('.slide-caption').forEach(el => el.classList.remove('animated'));\r\n");
      out.write("    },\r\n");
      out.write("    slideChangeTransitionEnd: function () {\r\n");
      out.write("      const activeCaption = document.querySelector('.swiper-slide-active .slide-caption');\r\n");
      out.write("      if (activeCaption) activeCaption.classList.add('animated');\r\n");
      out.write("    }\r\n");
      out.write("  }\r\n");
      out.write("});\r\n");
      out.write("\r\n");
      out.write("// ===== Progress Circle (dynamic + cinematic) =====\r\n");
      out.write("const circleEl = document.getElementById('progressCircle');\r\n");
      out.write("const ctx2d = circleEl.getContext('2d');\r\n");
      out.write("const progressText = document.getElementById('progressText');\r\n");
      out.write("const growthText = document.getElementById('growthMsg');\r\n");
      out.write("const headingEl = document.getElementById('progressHeading');\r\n");
      out.write("const revenueVal = ");
      out.print( revenue );
      out.write(";   // from backend\r\n");
      out.write("\r\n");
      out.write("function formatMoney(value) {\r\n");
      out.write("  return \"$\" + Number(value).toLocaleString(undefined, {\r\n");
      out.write("    minimumFractionDigits: 2, maximumFractionDigits: 2\r\n");
      out.write("  });\r\n");
      out.write("}\r\n");
      out.write("function getGrowthMsg(val, percent) {\r\n");
      out.write("  if (percent <= 0) return \"🚫 No growth yet, keep pushing!\";\r\n");
      out.write("  if (percent < 30) return \"🌱 Low Growth\";\r\n");
      out.write("  if (percent < 70) return \"📈 Moderate Growth\";\r\n");
      out.write("  if (percent < 100) return \"🚀 High Growth\";\r\n");
      out.write("  return \"🌟 Outstanding!\";\r\n");
      out.write("}\r\n");
      out.write("function getGlowColor(percent) {\r\n");
      out.write("  if (percent <= 30) return \"#ff4d4d\";\r\n");
      out.write("  if (percent <= 70) return \"#ffcc00\";\r\n");
      out.write("  return \"#00e676\";\r\n");
      out.write("}\r\n");
      out.write("function drawCircle(progress) {\r\n");
      out.write("  const w = circleEl.width, h = circleEl.height;\r\n");
      out.write("  const cx = w / 2, cy = h / 2, r = 85;\r\n");
      out.write("  ctx2d.clearRect(0, 0, w, h);\r\n");
      out.write("  ctx2d.lineWidth = 16; ctx2d.lineCap = 'round';\r\n");
      out.write("  ctx2d.beginPath(); ctx2d.strokeStyle = \"#2a2a3d\"; ctx2d.arc(cx, cy, r, 0, Math.PI * 2); ctx2d.stroke();\r\n");
      out.write("  const glowColor = getGlowColor(progress);\r\n");
      out.write("  ctx2d.shadowColor = glowColor; ctx2d.shadowBlur = 18;\r\n");
      out.write("  const start = -Math.PI / 2, end = start + (Math.PI * 2) * (progress / 100);\r\n");
      out.write("  ctx2d.beginPath(); ctx2d.strokeStyle = glowColor; ctx2d.arc(cx, cy, r, start, end); ctx2d.stroke();\r\n");
      out.write("  ctx2d.shadowBlur = 0;\r\n");
      out.write("  progressText.textContent = Math.round(progress) + '%';\r\n");
      out.write("  progressText.style.color = glowColor;\r\n");
      out.write("  progressText.style.textShadow = `0 0 15px ");
      out.write((java.lang.String) org.apache.jasper.runtime.PageContextImpl.proprietaryEvaluate("${glowColor}", java.lang.String.class, (jakarta.servlet.jsp.PageContext)_jspx_page_context, null));
      out.write("`;\r\n");
      out.write("}\r\n");
      out.write("function easeOutCubic(t) { return 1 - Math.pow(1 - t, 3); }\r\n");
      out.write("function animateCircleTo(targetPercent, duration = 1400, onComplete) {\r\n");
      out.write("  const startTime = performance.now();\r\n");
      out.write("  function step(now) {\r\n");
      out.write("    const elapsed = now - startTime;\r\n");
      out.write("    const t = Math.min(elapsed / duration, 1);\r\n");
      out.write("    const eased = easeOutCubic(t);\r\n");
      out.write("    const current = targetPercent * eased;\r\n");
      out.write("    drawCircle(current);\r\n");
      out.write("    if (t < 1) requestAnimationFrame(step);\r\n");
      out.write("    else if (onComplete) onComplete();\r\n");
      out.write("  }\r\n");
      out.write("  requestAnimationFrame(step);\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// ===== Editable Target Revenue =====\r\n");
      out.write("const targetSpan = document.getElementById(\"targetValue\");\r\n");
      out.write("const editBtn = document.getElementById(\"editTargetBtn\");\r\n");
      out.write("const progressValEl = document.getElementById(\"progressValue\");\r\n");
      out.write("\r\n");
      out.write("function recalcAndAnimate() {\r\n");
      out.write("  const target = Number(localStorage.getItem(\"targetRevenue\")) || 5000;\r\n");
      out.write("  const percent = Math.min(100, Math.round((revenueVal / target) * 100));\r\n");
      out.write("  targetSpan.textContent = formatMoney(target);\r\n");
      out.write("  progressValEl.textContent = formatMoney(revenueVal);\r\n");
      out.write("  animateCircleTo(percent, 1400, () => {\r\n");
      out.write("    growthText.textContent = getGrowthMsg(revenueVal, percent);\r\n");
      out.write("    growthText.classList.add(\"show\");\r\n");
      out.write("    if (headingEl) headingEl.classList.add(\"animate\");\r\n");
      out.write("  });\r\n");
      out.write("}\r\n");
      out.write("if (targetSpan && editBtn) {\r\n");
      out.write("  editBtn.addEventListener(\"click\", () => {\r\n");
      out.write("    const currentVal = targetSpan.textContent.replace(/[^0-9]/g, \"\");\r\n");
      out.write("    const input = document.createElement(\"input\");\r\n");
      out.write("    input.type = \"number\"; input.value = currentVal || 5000; input.style.width = \"90px\";\r\n");
      out.write("    targetSpan.replaceWith(input); input.focus();\r\n");
      out.write("    function saveTarget() {\r\n");
      out.write("      const newVal = parseInt(input.value) || 5000;\r\n");
      out.write("      targetSpan.textContent = formatMoney(newVal);\r\n");
      out.write("      input.replaceWith(targetSpan);\r\n");
      out.write("      localStorage.setItem(\"targetRevenue\", newVal);\r\n");
      out.write("      recalcAndAnimate();\r\n");
      out.write("    }\r\n");
      out.write("    input.addEventListener(\"blur\", saveTarget);\r\n");
      out.write("    input.addEventListener(\"keypress\", e => { if (e.key === \"Enter\") saveTarget(); });\r\n");
      out.write("  });\r\n");
      out.write("  const savedTarget = localStorage.getItem(\"targetRevenue\");\r\n");
      out.write("  if (savedTarget) targetSpan.textContent = formatMoney(savedTarget);\r\n");
      out.write("}\r\n");
      out.write("const progressCardEl = document.getElementById('progressCard');\r\n");
      out.write("if ('IntersectionObserver' in window) {\r\n");
      out.write("  const io = new IntersectionObserver((entries) => {\r\n");
      out.write("    entries.forEach(entry => { if (entry.isIntersecting) { recalcAndAnimate(); io.unobserve(entry.target); } });\r\n");
      out.write("  }, { threshold: 0.5 });\r\n");
      out.write("  io.observe(progressCardEl);\r\n");
      out.write("} else { recalcAndAnimate(); }\r\n");
      out.write("\r\n");
      out.write("// ===== Animate Product Cards =====\r\n");
      out.write("const productCards = document.querySelectorAll('.product-card');\r\n");
      out.write("const revealObserver = new IntersectionObserver(entries => {\r\n");
      out.write("  entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); });\r\n");
      out.write("}, { threshold: 0.22 });\r\n");
      out.write("productCards.forEach(card => revealObserver.observe(card));\r\n");
      out.write("\r\n");
      out.write("// ===== Sidebar Toggle =====\r\n");
      out.write("const sidebar = document.getElementById('sidebar');\r\n");
      out.write("const sidebarToggle = document.getElementById('sidebarToggle');\r\n");
      out.write("if (sidebar && sidebarToggle){\r\n");
      out.write("  sidebarToggle.addEventListener('click', () => {\r\n");
      out.write("    sidebar.classList.toggle('active');\r\n");
      out.write("    const open = sidebar.classList.contains('active');\r\n");
      out.write("    sidebar.setAttribute('aria-hidden', open ? 'false' : 'true');\r\n");
      out.write("  });\r\n");
      out.write("}\r\n");
      out.write("//===== Tabs =====\r\n");
      out.write("const notesTab = document.getElementById('notesTab');\r\n");
      out.write("const todoTab = document.getElementById('todoTab');\r\n");
      out.write("const notesContent = document.getElementById('notesContent');\r\n");
      out.write("const todoContent = document.getElementById('todoContent');\r\n");
      out.write("if (notesTab && todoTab){\r\n");
      out.write("  notesTab.addEventListener('click', () => {\r\n");
      out.write("    notesTab.classList.add('active'); todoTab.classList.remove('active');\r\n");
      out.write("    notesContent.classList.add('active'); todoContent.classList.remove('active');\r\n");
      out.write("  });\r\n");
      out.write("  todoTab.addEventListener('click', () => {\r\n");
      out.write("    todoTab.classList.add('active'); notesTab.classList.remove('active');\r\n");
      out.write("    todoContent.classList.add('active'); notesContent.classList.remove('active');\r\n");
      out.write("  });\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("// ===== Notes + Tasks LocalStorage =====\r\n");
      out.write("const noteInput = document.getElementById('noteInput'),\r\n");
      out.write("      notesList = document.getElementById('notesList');\r\n");
      out.write("const todoInput = document.getElementById('todoInput'),\r\n");
      out.write("      todoList = document.getElementById('todoList');\r\n");
      out.write("const toast = document.getElementById('toast');\r\n");
      out.write("\r\n");
      out.write("function showToast(msg){\r\n");
      out.write("  toast.textContent = msg;\r\n");
      out.write("  toast.classList.add(\"show\");\r\n");
      out.write("  setTimeout(()=>toast.classList.remove(\"show\"), 2000);\r\n");
      out.write("}\r\n");
      out.write("\r\n");
      out.write("function loadData(key, list, type){\r\n");
      out.write("  const data = JSON.parse(localStorage.getItem(key) || '[]');\r\n");
      out.write("  list.innerHTML = '';\r\n");
      out.write("  data.forEach((t, i) => {\r\n");
      out.write("    const li = document.createElement('li');\r\n");
      out.write("    const span = document.createElement('span');\r\n");
      out.write("    span.textContent = t;\r\n");
      out.write("    li.appendChild(span);\r\n");
      out.write("\r\n");
      out.write("    const actions = document.createElement('div');\r\n");
      out.write("    actions.className=\"actions\";\r\n");
      out.write("\r\n");
      out.write("    if (type === 'notes'){\r\n");
      out.write("      const editBtn = document.createElement('button');\r\n");
      out.write("      editBtn.textContent = '✏️';\r\n");
      out.write("      editBtn.className = \"editBtn\";\r\n");
      out.write("      editBtn.onclick = () => {\r\n");
      out.write("        const newText = prompt(\"Edit your note:\", t);\r\n");
      out.write("        if(newText){\r\n");
      out.write("          data[i] = newText;\r\n");
      out.write("          localStorage.setItem(key, JSON.stringify(data));\r\n");
      out.write("          loadData(key, list, type);\r\n");
      out.write("          showToast(\"Note updated ✏️\");\r\n");
      out.write("        }\r\n");
      out.write("      };\r\n");
      out.write("      actions.appendChild(editBtn);\r\n");
      out.write("    }\r\n");
      out.write("\r\n");
      out.write("    const btn = document.createElement('button');\r\n");
